typedef enum
{
    STATE_INIT,
    STATE_IDLE,
    STATE_ACTIVE,
    STATE_FAULT
} AppState;

void App_Dispatch(AppState *state, unsigned event)
{
    switch (*state)
    {
        case STATE_INIT:   *state = STATE_IDLE; break;
        case STATE_IDLE:   if (event == 1u) *state = STATE_ACTIVE; break;
        case STATE_ACTIVE: if (event == 2u) *state = STATE_FAULT; break;
        case STATE_FAULT:  SafeOutputs(); break;
    }
}

typedef struct
{
    uint32_t period_ms;
    uint32_t deadline_ms;
} PeriodicJob;

bool PeriodicJob_Due(PeriodicJob *job, uint32_t now_ms)
{
    if ((int32_t)(now_ms - job->deadline_ms) < 0)
    {
        return false;
    }

    job->deadline_ms += job->period_ms;
    return true;
}

bool DeadlineExpired(uint32_t now_ms, uint32_t deadline_ms)
{
    return (int32_t)(now_ms - deadline_ms) >= 0;
}

typedef struct
{
    bool stable;
    bool previous_raw;
    uint32_t changed_at_ms;
} Debouncer;

bool Debouncer_Update(Debouncer *db, bool raw, uint32_t now_ms, uint32_t delay_ms)
{
    if (raw != db->previous_raw)
    {
        db->previous_raw = raw;
        db->changed_at_ms = now_ms;
    }

    if ((uint32_t)(now_ms - db->changed_at_ms) >= delay_ms)
    {
        db->stable = raw;
    }

    return db->stable;
}

