#define RX_CAPACITY 128u

typedef struct
{
    uint8_t data[RX_CAPACITY];
    volatile uint16_t write_index;
    volatile uint16_t read_index;
} ByteRing;

bool ByteRing_PushFromIsr(ByteRing *ring, uint8_t value)
{
    const uint16_t next = (uint16_t)((ring->write_index + 1u) % RX_CAPACITY);
    if (next == ring->read_index)
    {
        return false;
    }

    ring->data[ring->write_index] = value;
    ring->write_index = next;
    return true;
}

bool ByteRing_Pop(ByteRing *ring, uint8_t *value)
{
    if (ring->read_index == ring->write_index)
    {
        return false;
    }

    *value = ring->data[ring->read_index];
    ring->read_index = (uint16_t)((ring->read_index + 1u) % RX_CAPACITY);
    return true;
}

