uint16_t Crc16Modbus(const uint8_t *data, size_t size)
{
    uint16_t crc = 0xFFFFu;

    for (size_t i = 0; i < size; ++i)
    {
        crc ^= data[i];
        for (unsigned bit = 0; bit < 8u; ++bit)
        {
            crc = (crc & 1u) ? (uint16_t)((crc >> 1u) ^ 0xA001u)
                             : (uint16_t)(crc >> 1u);
        }
    }

    return crc;
}

