hw_timer_t *timer = nullptr;
SemaphoreHandle_t timer_semaphore;
portMUX_TYPE timer_mux = portMUX_INITIALIZER_UNLOCKED;
volatile uint32_t isr_count = 0;

void ARDUINO_ISR_ATTR OnTimer()
{
    portENTER_CRITICAL_ISR(&timer_mux);
    ++isr_count;
    portEXIT_CRITICAL_ISR(&timer_mux);
    xSemaphoreGiveFromISR(timer_semaphore, nullptr);
}

void setup()
{
    timer_semaphore = xSemaphoreCreateBinary();
    timer = timerBegin(1'000'000);       // 1 MHz timer frequency
    timerAttachInterrupt(timer, &OnTimer);
    timerAlarm(timer, 1'000'000, true, 0); // every second
}

void ARDUINO_ISR_ATTR OnTimerWithContext(void *context)
{
    auto *counter = static_cast<volatile uint32_t *>(context);
    ++(*counter);
}

timerAttachInterruptArg(timer, &OnTimerWithContext, (void *)&isr_count);

uint32_t SnapshotIsrCount()
{
    portENTER_CRITICAL(&timer_mux);
    const uint32_t snapshot = isr_count;
    portEXIT_CRITICAL(&timer_mux);
    return snapshot;
}

